23	
24		-- Wait for a given time and check if the signal is idle
25		procedure CheckNoActivity(signal Sig : in std_logic;
26		                          IdleTime   : in time;
27		                          Level      : in integer range -1 to 1; -- -1 = don't check, 0 = low, 1 = high
28		                          Msg        : in string := "";
