34		                              Msg        : in string := "";
35		                              Prefix     : in string := "###ERROR###: ");
36	
37		-- Check when a signal had its last activity (without waiting)
38		procedure CheckLastActivity(signal Sig : in std_logic;
39		                            IdleTime   : in time;
40		                            Level      : in integer range -1 to 1; -- -1 = don't check, 0 = low, 1 = high
41		                            Msg        : in string := "";
42		                            Prefix     : in string := "###ERROR###: ");
43	
44		procedure CheckLastActivityStlv(signal Sig : in std_logic_vector;
45		                                IdleTime   : in time;
46		                                Level      : in integer range -1 to integer'high; -- -1 = don't check, otherwise interpreted unsigned
47		                                Msg        : in string := "";
48		                                Prefix     : in string := "###ERROR###: ");
49	
50		-- pulse a signal
51		procedure PulseSig(signal Sig : out std_logic;
52		                   signal Clk : in std_logic);
53	
54		-- Clocked wait for a signal
55		procedure ClockedWaitFor(Val        : in std_logic;
56		                         signal Sig : in std_logic;
57		                         signal Clk : in std_logic);
58								 
59		-- Wait for a number of clock cycles
60		procedure WaitClockCycles(	Cycles     : in integer;
61									signal Clk : in std_logic);	
62					
63		-- Wait for a time and quit on rising edge
64		procedure ClockedWaitTime(	Duration   	: in time;
65									signal Clk 	: in std_logic);	
66	
67		-- Strobe generator
68		procedure GenerateStrobe(	freq_clock 	 : in real      := 100.0E6; -- in Hz
69									freq_str   	 : in real      := 1.0E6; 	-- in Hz
70									rst_pol_g  	 : in std_logic := '1'; 	-- reset polarity
71									signal rst   : in std_logic; 			-- rst
72									signal clk   : in std_logic; 			-- clk
73									signal str   : out std_logic); 			-- str
74		
75		-- check if stdlv is arrived within a defined period of time
76		procedure WaitForValueStdlv(signal Sig		: in std_logic_vector; 		-- Signal to check
77									ExpVal			: in std_logic_vector; 		-- expected value
78									Timeout	  		: in time;					-- time to wait for
79									Msg		  		: in string;				-- msg to display
80									Prefix     		: in string := "###ERROR###: ");   			-- bool out to stop Tb for ex.
81								
82		-- check if std is arrived within a defined period of time
83		procedure WaitForValueStdl(	signal Sig		: in std_logic; 			-- Signal to check
84									ExpVal			: in std_logic; 			-- expected value
85									Timeout	  		: in time;					-- time to wait for
86									Msg		  		: in string;				-- msg to display
87									Prefix     		: in string := "###ERROR###: ");   			-- bool out to stop Tb for ex.						
88	
89	end psi_tb_activity_pkg;
