91	------------------------------------------------------------------------------
92	-- Package Body
93	------------------------------------------------------------------------------
94	package body psi_tb_activity_pkg is
95	
96		-- *** CheckNoActivity ***
97		procedure CheckNoActivity(signal Sig : in std_logic;
98		                          IdleTime   : in time;
99		                          Level      : in integer range -1 to 1; -- -1 = don't check, 0 = low, 1 = high
100		                          Msg        : in string := "";
101		                          Prefix     : in string := "###ERROR###: ") is
102		begin
103			wait for IdleTime;
104			assert Sig'last_event >= IdleTime
105			report Prefix & Msg & "[Unexpected Activity]"
106			severity error;
107			if Level /= -1 then
108				StdlCompare(Level, Sig, "CheckNoActivity: " & Msg, Prefix);
109			end if;
110		end procedure;
111	
112		-- *** CheckNoActivityStlv ***
113		procedure CheckNoActivityStlv(signal Sig : in std_logic_vector;
114		                              IdleTime   : in time;
115		                              Level      : in integer range -1 to integer'high; -- -1 = don't check, otherwise interpreted unsigned
116		                              Msg        : in string := "";
117		                              Prefix     : in string := "###ERROR###: ") is
118		begin
119			wait for IdleTime;
120			assert Sig'last_event >= IdleTime
121			report Prefix & Msg & "[Unexpected Activity]"
122			severity error;
123			if Level /= -1 then
124				StdlvCompareInt(Level, Sig, "CheckNoActivityStlv: " & Msg, false, 0, Prefix);
125			end if;
126		end procedure;
127	
128		-- *** CheckLastActivity ***
129		procedure CheckLastActivity(signal Sig : in std_logic;
130		                            IdleTime   : in time;
131		                            Level      : in integer range -1 to 1; -- -1 = don't check, 0 = low, 1 = high
132		                            Msg        : in string := "";
133		                            Prefix     : in string := "###ERROR###: ") is
134		begin
135			assert Sig'last_event >= IdleTime
136			report Prefix & Msg & "Unexpected activity, " &
137						"[Expeced idle " & time'image(IdleTime) &
138						", Actual idle " & time'image(Sig'last_event) & "]"
139			severity error;
140			if Level /= -1 then
141				StdlCompare(Level, Sig, "CheckLastActivity: " & Msg, Prefix);
142			end if;
143		end procedure;
144	
145		-- *** CheckLastActivityStlv ***
146		procedure CheckLastActivityStlv(signal Sig : in std_logic_vector;
147		                                IdleTime   : in time;
148		                                Level      : in integer range -1 to integer'high; -- -1 = don't check, otherwise interpreted unsigned
149		                                Msg        : in string := "";
150		                                Prefix     : in string := "###ERROR###: ") is
151		begin
152			assert Sig'last_event >= IdleTime
153			report Prefix & Msg & "Unexpected activity, " &
154						"[Expeced idle " & time'image(IdleTime) &
155						", Actual idle " & time'image(Sig'last_event) & "]"
156			severity error;
157			if Level /= -1 then
158				StdlvCompareInt(Level, Sig, "CheckLastActivityStlv: " & Msg, false, 0, Prefix);
159			end if;
160		end procedure;
161	
162		-- *** PulseSig ***
163		procedure PulseSig(signal Sig : out std_logic;
164		                   signal Clk : in std_logic) is
165		begin
166			wait until rising_edge(Clk);
167			Sig <= '1';
168			wait until rising_edge(Clk);
169			Sig <= '0';
170		end procedure;
171	
172		-- *** ClockedWaitFor ***
173		procedure ClockedWaitFor(Val        : in std_logic;
174		                         signal Sig : in std_logic;
175		                         signal Clk : in std_logic) is
176		begin
177			wait until rising_edge(Clk) and Sig = Val;
178		end procedure;
179		
180		-- *** ClockedWaitFor ***
181		procedure WaitClockCycles(	Cycles     : in integer;
182									signal Clk : in std_logic) is
183		begin
184			for i in 0 to Cycles-1 loop
185				wait until rising_edge(Clk);
186			end loop;
187		end procedure;
188		
189		-- *** ClockedWaitTime ***
190		procedure ClockedWaitTime(	Duration   	: in time;
191									signal Clk 	: in std_logic) is
192		begin
193			wait for Duration;
194			wait until rising_edge(Clk);
195		end procedure;
196	
197		-- *** GenerateStrobe ***
198		procedure GenerateStrobe(	freq_clock 			: in real      := 100.0E6;
199									freq_str   			: in real      := 1.0E6;
200									rst_pol_g  			: in std_logic := '1';
201									signal rst          : in std_logic;
202									signal clk        	: in std_logic;
203									signal str          : out std_logic) is
204	
205			variable count_v : integer range 0 to (integer(ceil(freq_clock/freq_str))) := 0;
206		begin
207			while true loop
208			wait until rising_edge(clk);
209			if rst = rst_pol_g then
210				count_v := 0;
211				str     <= '0';
212			else
213				if count_v /= integer(ceil(freq_clock/freq_str)) - 1 then
214					str     <= '0';
215					count_v := count_v + 1;
216				else
217					str     <= '1';
218					count_v := 0;
219				end if;
220			end if;
221			end loop;
222		end procedure;
223	
224		-- *** Wait for Standard logic vector to happen ***
225		procedure WaitForValueStdlv(signal Sig		: in std_logic_vector;
226									ExpVal			: in std_logic_vector;
227									Timeout	  		: in time;
228									Msg		  		: in string;
229									Prefix     		: in string := "###ERROR###: ") is
230		begin
231			wait until ExpVal = Sig for timeout;
232			if ExpVal /= Sig then
233				report 	Prefix & Msg & 
234					" Target state not reached" &
235					" [Expected " & str(ExpVal) & "(0x" & hstr(ExpVal) & ")" &
236					", Received " & str(Sig) & "(0x" & hstr(Sig) & ")" & "]"
237					severity error;
238			end if;
239		end procedure;
240		
241		-- *** Wait for Standard logic to happen ***
242		procedure WaitForValueStdl(	signal Sig		: in std_logic;
243									ExpVal			: in std_logic;
244									Timeout	  		: in time;
245									Msg		  		: in string;
246									Prefix     		: in string := "###ERROR###: ") is
247		begin
248			wait until ExpVal = Sig for timeout;
249			if ExpVal /= Sig then
250				report Prefix & msg & 
251					" Target state not reached" &
252					" [Expected " & str(ExpVal) & 
253					", Received " & str(Sig) & "]" 
254					severity error;
255			end if;
256		end procedure;
257	
258	end psi_tb_activity_pkg;
