4	--  Authors: Oliver Bruendler, Benoit Stef, Radoslaw Rybaniec
5	------------------------------------------------------------------------------
6	
7	-- This package implements simple reading and writing from and to textfiles
8	-- as required by many bittrue simulations.
9	--
10	-- It is assumed that signal values are given in textfiles as integer values,
11	-- one column per signal, columns separated by spaces (NOT Commas).
12	--
13	-- Example:
14	-- 117 124 -45
15	-- 111 -123 88
16	--
17	-- Example code for producing such files from python:
18	-- import numpy as np
19	-- a = np.linspace(100, 200, 10)
20	-- b = np.linspace(300, 400, 10)
21	-- np.savetxt("test.txt", np.column_stack((a, b)), fmt="%i")
22	
23	------------------------------------------------------------------------------
24	-- Libraries
25	------------------------------------------------------------------------------
26	library ieee;
27	use ieee.std_logic_1164.all;
28	use ieee.numeric_std.all;
29	
30	library std;
31	use std.textio.all;
32	
33	library work;
34	use work.psi_tb_txt_util.all;
35	
36	------------------------------------------------------------------------------
37	-- Package Header
38	------------------------------------------------------------------------------
39	package psi_tb_textfile_pkg is
40	
41	   type TextfileData_t is array (natural range <>) of integer;
42	   --type TextfileFormat_t is array (natural range <>) of PsiFixFmt_t;
43	   type TextfileName_t is array (natural range <>) of string;
44	
45	   -- Signal definitions to pass for constant values or unused signals (signals are not allowed to be left open in procedure declarations)
46	   signal PsiTextfile_SigOne       : std_logic := '1';
47	   signal PsiTextfile_SigUnused    : std_logic;
48	   signal PsiTextfile_SigUnusedVec : std_logic_vector(0 downto 0);
49	   signal PsiTextfile_SigUnusedData   : TextfileData_t(0 downto 0);
50	
51	   -- Read a textfile and apply it to signals column by column
52	   procedure ApplyTextfileContent(signal Clk  : in std_logic;
53	                                   signal Rdy  : in std_logic; -- Pass PsiTextfile_SigOne if Rdy is not used
54	                                   signal Vld  : out std_logic;
55	                                   signal Data : out TextfileData_t;
56	                                   Filepath    : in string;
57	                                   ClkPerSpl   : in positive  := 1;
58	                                   MaxLines    : in integer   := -1; -- -1 = infinite, else number of lines
59	                                   IgnoreLines : in natural   := 0;
60	                                   DataOnlyOnVld : in boolean := false);
61	
62	   -- Read a textfile and compare it column by column to signals
63	   procedure CheckTextfileContent(signal Clk    : in std_logic;
64	                                    signal Rdy    : out std_logic; -- Pass PsiTextfile_SigUnused if Rdy is not used
65	                                    signal Vld    : in std_logic;
66	                                    signal Data   : in TextfileData_t;
67	                                    Filepath      : in string;
68	                                    ClkPerSpl     : in positive := 1;
69	                                    ErrorPrefix   : in string   := "###ERROR###";
70	                                    MaxLines      : in integer  := -1; -- -1 = infinite, else number of lines      
71	                                    IgnoreLines   : in natural  := 0;
72	                                    Tolerance     : in natural  := 0);
73	
74	   -- write a textfile with header line 1 name of data & second line FixPoint format
75	   procedure WriteTextfile(signal Clk        : in std_logic;
76	                            signal Vld        : in std_logic;
77	                            signal Data       : in TextfileData_t;
78	                            constant nb_data  : integer;
79	                            constant time_sim : boolean   := true;
80	                            Name              : in TextfileName_t;
81	                            spacer            : in string := " , ";
82	                            Filepath          : in string := "/data/processing_data.txt"); --filepath & name
83	
84	end package;
85	
86	------------------------------------------------------------------------------
87	-- Package Body
88	------------------------------------------------------------------------------
89	package body psi_tb_textfile_pkg is
90	
91	   -- Read a textfile and apply it to signals column by column
92	   procedure ApplyTextfileContent( signal Clk  : in std_logic;
93	                                   signal Rdy  : in std_logic;
94	                                   signal Vld  : out std_logic;
95	                                   signal Data : out TextfileData_t;
96	                                   Filepath    : in string;
97	                                   ClkPerSpl   : in positive  := 1;
98	                                   MaxLines    : in integer   := -1;
99	                                   IgnoreLines : in natural   := 0;
100	                                   DataOnlyOnVld : in boolean := false) is
101	      file fp         : text;
102	      variable ln     : line;
103	      variable Spl    : integer;
104	      variable lineNr : integer := 1;
105	   begin
106	      -- Open File
107	      file_open(fp, Filepath, read_mode);
108	
109	      -- Apply input
110	      wait until rising_edge(Clk);
111	      while (not endfile(fp)) and ((lineNr <= MaxLines) or (MaxLines < 0)) loop
112	         -- Ignore header lines if required
113	         readline(fp, ln);
114	         if lineNr > IgnoreLines then
115	            Vld <= '1';
116	            for idx in 0 to Data'length - 1 loop
117	               read(ln, Spl);
118	               Data(idx) <= Spl;
119	            end loop;
120	            wait until rising_edge(Clk) and Rdy = '1';
121	            if ClkPerSpl > 1 then
122	               if DataOnlyOnVld then
123	                  Data <= (Data'range => 0);
124	               end if;
125	               Vld <= '0';
126	               for i in 0 to ClkPerSpl - 2 loop
127	                  wait until rising_edge(Clk);
128	               end loop;
129	            end if;
130	         end if;
131	         lineNr := lineNr + 1;
132	      end loop;
133	      Vld <= '0';
134	
135	      -- Close File
136	      file_close(fp);
137	   end procedure;
138	
139	   -- Read a textfile and compare it column by column to signals
140	   procedure CheckTextfileContent(  signal Clk    : in std_logic;
141	                                    signal Rdy    : out std_logic;
142	                                    signal Vld    : in std_logic;
143	                                    signal Data   : in TextfileData_t;
144	                                    Filepath      : in string;
145	                                    ClkPerSpl     : in positive := 1;
146	                                    ErrorPrefix   : in string   := "###ERROR###";
147	                                    MaxLines      : in integer := -1;
148	                                    IgnoreLines   : in natural := 0;
149	                                    Tolerance     : in natural := 0) is
150	      file fp         : text;
151	      variable ln     : line;
152	      variable Spl    : integer;
153	      variable Sig    : integer;
154	      variable lineNr : integer := 1;
155	      variable colNr  : integer := 1;
156	   begin
157	      -- Open File
158	      file_open(fp, Filepath, read_mode);
159	
160	      -- Check output
161	      while (not endfile(fp)) and ((lineNr <= MaxLines) or (MaxLines < 0)) loop
162	         -- Ignore header lines if required      
163	         readline(fp, ln);
164	         if lineNr > IgnoreLines then
165	
166	            -- Wait for sample point
167	            Rdy <= '1';
168	            wait until rising_edge(Clk) and Vld = '1';
169	
170	            -- Check data
171	            colNr := 0;
172	            for idx in 0 to Data'length - 1 loop
173	               read(ln, Spl);
174	               Sig := Data(idx);
175	               assert abs(Sig - Spl) <= Tolerance
176	               report ErrorPrefix & ": Wrong Sample, line=" & integer'image(lineNr) & " column=" & integer'image(colNr) & LF &
177	                        " --> Expected " & integer'image(Spl) & " [0x" & hstr(std_logic_vector(to_signed(Spl, 32))) & "]" & LF &
178	                        " --> Received " & integer'image(Sig) & " [0x" & hstr(std_logic_vector(to_signed(Sig, 32))) & "]"
179	               severity error;
180	               colNr := colNr + 1;
181	            end loop;
182	
183	            -- Wait for next sample before asserting ready
184	            if ClkPerSpl > 1 then
185	               Rdy <= '0';
