---I2C TB process structure---
36:	p_master : process
41:		wait for 1 us;
44:		print(">> Addressing");
47:		print("Do 7b address cycle without data, ACK, read");
51:		wait for 10 us;
54:		print("Do 7b address cycle without data, ACK, write");
58:		wait for 10 us;
61:		print("Do 7b address cycle without data, NACK, read");
65:		wait for 10 us;
68:		print("Do 10b address cycle without data, ACK, write");
72:		wait for 10 us;
75:		print("Do 10b address cycle without data, NACK, read");
79:		wait for 10 us;
82:		print(">> Data Transfers");
85:		print("Single Byte Read, ACK");
90:		wait for 10 us;
93:		print("Single Byte Read, NACK");
98:		wait for 10 us;
101:		print("Two Byte Read");
107:		wait for 10 us;
110:		print("Single Byte Write, ACK");
115:		wait for 10 us;
118:		print("Single Byte Write, NACK");
123:		wait for 10 us;
126:		print("Two Byte Write");
132:		wait for 10 us;	
135:		print(">> Repeated Start (Mixed Transfer)");	
138:		print("1 Byte Write, Then 1 Byte Read");
146:		wait for 10 us;
149:		print(">> Clock Stretching");
152:		print("Single Byte Read");
157:		wait for 10 us;
159:		print("Single Byte Write");
164:		wait for 10 us;
167:	end process;
171:	p_slave : process
179:		I2cSlaveWaitStart(scl, sda, "S: 7b wait start");
180:		I2cSlaveExpectAddr(16#12#, true, scl, sda, "S: 7b check address", 7);
181:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
184:		I2cSlaveWaitStart(scl, sda, "S: 7b wait start");
185:		I2cSlaveExpectAddr(16#13#, false, scl, sda, "S: 7b check address", 7);
186:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
189:		I2cSlaveWaitStart(scl, sda, "S: 7b wait start");
190:		I2cSlaveExpectAddr(16#12#, true, scl, sda, "S: 7b check address", 7, '1');
191:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
194:		I2cSlaveWaitStart(scl, sda, "S: 10b wait start");
195:		I2cSlaveExpectAddr(16#113#, false, scl, sda, "S: 10b check address", 10);
196:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
199:		I2cSlaveWaitStart(scl, sda, "S: 10b wait start");
200:		I2cSlaveExpectAddr(16#112#, true, scl, sda, "S: 10b check address", 10, '1');
201:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
205:		I2cSlaveWaitStart(scl, sda, "S: wait start");
206:		I2cSlaveExpectAddr(16#13#, true, scl, sda, "S: check address", 7);
207:		I2cSlaveSendByte(16#AB#, scl, sda, "S: data-read");
208:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
211:		I2cSlaveWaitStart(scl, sda, "S: wait start");
212:		I2cSlaveExpectAddr(16#13#, true, scl, sda, "S: check address", 7);
213:		I2cSlaveSendByte(16#AB#, scl, sda, "S: data-read", '1');
214:		I2cSlaveWaitStop(scl, sda, "S: wait stop");
217:		I2cSlaveWaitStart(scl, sda, "S: wait start");

